def decode_hash_u_escapes_text(value: str) -> str:
    """Decode filenames produced as #U4e2d#U6587 after ZIP/Windows transfers."""
    s = str(value or "")
    try:
        return re.sub(r"#U([0-9a-fA-F]{4,6})", lambda m: chr(int(m.group(1), 16)), s)
    except Exception:
        return s



