def infer_visual_role_from_image_name(image_path: str, prompt: str = "", forced_role: str = "auto") -> str:
    """手动文件夹后处理时，根据文件名和可选提示词判断页型。"""
    role = normalize_postprocess_role(forced_role)
    if role != "auto":
        return role
    name = decode_hash_u_escapes_text(os.path.splitext(os.path.basename(str(image_path or "")))[0])
    prompt = decode_hash_u_escapes_text(str(prompt or ""))
    combined = f"{name}\n{prompt}".lower()
    if re.search(r"推文图\s*[_\- ]?0?1|tweet[_\- ]?cover|wechat[_\- ]?cover", combined, flags=re.I):
        return "tweet_cover_27_36"
    if re.search(r"(?:^|[^a-z])a01(?:[^a-z]|$)|bilibili[_\- ]?cover|b站封面|哔哩哔哩封面", combined, flags=re.I):
        return "bilibili_cover_4_3"
    if re.search(r"(?:^|[^a-z])a02(?:[^a-z]|$)|bilibili[_\- ]?home|b站首页|哔哩哔哩首页", combined, flags=re.I):
        return "bilibili_home_16_9"
    if (re.search(r"(?:^|[^a-z])c(?:[^a-z]|$)|(brand|ending|end[_\- ]?page|final[_\- ]?page|尾页|品牌页|结束页|关注页)", name, flags=re.I)
            or re.search(r"(brand\s*(?:end|page)|ending\s*brand|end[_\- ]?page|final[_\- ]?page|尾页|品牌页|结束页|关注页)", prompt, flags=re.I)):
        return "brand_end_page_27_48"
    if re.search(r"(?:^|[^a-z])a2(?:[^a-z]|$)|home\s*page|首页|图[_\- ]?0?2|镜头[_\- ]?0?2|shot[_\- ]?0?2", combined, flags=re.I):
        return "home_page_27_48"
    if re.search(r"(?:^|[^a-z])a1(?:[^a-z]|$)|cover|title[_\- ]?page|chapter[_\- ]?cover|封面|片头|镜头[_\- ]?0?1|shot[_\- ]?0?1", combined, flags=re.I):
        return "tweet_cover_27_36"
    if re.search(r"(?:^|[^a-z])b\d{1,2}(?:[^a-z]|$)", combined, flags=re.I):
        return "content_diagram_27_48"
    if prompt:
        return detect_visual_role(name, prompt)
    return "content_diagram_27_48"



