        return ("16:9",) + _parse_exact_ratio_size_from_env("OPENAI_IMAGE_SIZE_A02_16_9", os.environ.get("OPENAI_IMAGE_SIZE_16_9", default_size), 1024 if TOKEN_SAVER_MODE else 1920, 576 if TOKEN_SAVER_MODE else 1080, ratio_w=16, ratio_h=9)
