GPT_IMAGE2_LOW_COST_SIZES = {
    "3:4": ("720x960", 720, 960),
    "9:16": ("720x1280", 720, 1280),
    "4:3": ("960x720", 960, 720),
    "16:9": ("1280x720", 1280, 720),
}


def _openai_api_safe_canvas_for_role(role: str):
    """Return the low-token GPT Image 2 request size for each role.

    Final exported platform images are still controlled by visual_role_canvas() and post-processing.
    This function only chooses the raw Image API request size. The defaults match the low-cost
    exact-ratio sizes requested for GPT Image 2: A1=720x960, B/C/A2=720x1280,
    A01=960x720, A02=1280x720. All edges are multiples of 16 and all pixel counts are above
    the 655,360 minimum.
    """
    role = normalize_postprocess_role(role)
    if role in {"tweet_cover_27_36", "cover_27_48"}:
        size, w, h = GPT_IMAGE2_LOW_COST_SIZES["3:4"]
        return ("3:4-api-lowcost", size, w, h)
    if role in {"home_page_27_48", "brand_end_page_27_48", "content_diagram_27_48"}:
        size, w, h = GPT_IMAGE2_LOW_COST_SIZES["9:16"]
        return ("9:16-api-lowcost", size, w, h)
    if role == "bilibili_cover_4_3":
        size, w, h = GPT_IMAGE2_LOW_COST_SIZES["4:3"]
        return ("4:3-api-lowcost", size, w, h)
    if role == "bilibili_home_16_9":
        size, w, h = GPT_IMAGE2_LOW_COST_SIZES["16:9"]
        return ("16:9-api-lowcost", size, w, h)
    if role == "daily_research_square_visual_summary":
        return ("1:1-api", "1024x1024", 1024, 1024)
    size, w, h = GPT_IMAGE2_LOW_COST_SIZES["9:16"]
    return ("9:16-api-lowcost", size, w, h)


def coerce_openai_image_request_size(role: str, requested_size: str, fallback_w: int, fallback_h: int):
    """Coerce a requested size to a safe OpenAI Images API size if needed.

    Always returns exactly four values: (ratio_label, size_string, width, height).
    The previous v5 build returned three values for already-valid sizes, which caused
    "not enough values to unpack (expected 4, got 3)" in the OpenAI image client.
    """
    w, h = parse_image_size(requested_size, fallback_w, fallback_h)
    if w > 0 and h > 0 and w % 16 == 0 and h % 16 == 0:
        if w == h:
            ratio = "1:1-api"
        elif w * 16 == h * 9:
            ratio = "9:16-api"
        elif w * 9 == h * 16:
            ratio = "16:9-api"
        elif w * 4 == h * 3:
            ratio = "3:4-api"
        elif w * 3 == h * 4:
            ratio = "4:3-api"
        else:
            ratio = "custom-api"
        return ratio, requested_size, w, h
    return _openai_api_safe_canvas_for_role(role)


def visual_generation_canvas(role: str):
    """图像 API 的实际生成画幅。A1/A2/A01/A02 只生成一次 1:1 Master Background，随后按平台比例裁切。

    注意：OpenAI Images API 要求 width/height 都能被 16 整除；因此这里返回“API 安全尺寸”，
    而最终输出规格仍由 visual_role_canvas() 和后处理裁切决定。
    """
    role = normalize_postprocess_role(role)
    if role in {"tweet_cover_27_36", "cover_27_48", "home_page_27_48", "bilibili_cover_4_3", "bilibili_home_16_9"}:
        # Only A1 should actually call the image model. A2/A01/A02 are derived crops.
        # Default request is the low-token 3:4 A1 master (720x960), not a square 1024x1024 image.
        size = os.environ.get("OPENAI_IMAGE_SIZE_A_MASTER", os.environ.get("OPENAI_IMAGE_SIZE_A1_3_4", "720x960"))
        _api_ratio, size, w, h = coerce_openai_image_request_size("tweet_cover_27_36", size, 720, 960)
        return "3:4-master-lowcost", size, w, h
    return _openai_api_safe_canvas_for_role(role if role != "auto" else "content_diagram_27_48")

def detect_visual_canvas_from_prompt(prompt: str):
    exact = re.search(
        r"(?:request\s+image\s+canvas\s+exactly|canvas\s+requirement.*?exactly|exactly)\s*(\d{3,5})\s*x\s*(\d{3,5})",
        str(prompt or ""),
        flags=re.I | re.S,
    )
    if exact:
        w = int(exact.group(1))
        h = int(exact.group(2))
        size = f"{w}x{h}"
        role = detect_visual_role("", prompt)
        return coerce_openai_image_request_size(role, size, w, h)
    role = detect_visual_role("", prompt)
    return visual_generation_canvas(role)


