def sanitize_content_prompt_brand_text(prompt: str) -> str:
    """内容图提示词禁止出现品牌字样，避免图像模型自己生成第二个 Logo。"""
    p = str(prompt or "")
    # 删除包含品牌字样的整句/从句；品牌由程序后处理统一叠加。
    p = re.sub(r"[^。.!?;；\n]*QuanLan\s*BrainScience\s*®?[^。.!?;；\n]*[。.!?;；]?", " ", p, flags=re.IGNORECASE)
    p = re.sub(r"[^。.!?;；\n]*(?:watermark|brand mark|brand logo|logo-like text|pseudo-watermark|channel name)[^。.!?;；\n]*[。.!?;；]?", " ", p, flags=re.IGNORECASE)
    p = re.sub(r"do not render[^。.!?;；\n]*", " ", p, flags=re.IGNORECASE)
    p = re.sub(r"software will overlay[^。.!?;；\n]*", " ", p, flags=re.IGNORECASE)
    p = re.sub(r"software-stamped[^。.!?;；\n]*", " ", p, flags=re.IGNORECASE)
    p = re.sub(r"\s+", " ", p).strip()
    return p


def sanitize_content_prompt_text_policy(prompt: str) -> str:
    """内容图主体提示词去掉与中间内容页无关的公共文字元素，避免书名、章节、作者等泄露到内容图里。"""
    p = str(prompt or "")
    forbidden_patterns = [
        r"[^。.!?;；\n]*(?:book\s*title|chapter\s*(?:title|number|info(?:rmation)?)|author\s*line|author(?:s)?|version\s*line|edition|subtitle|page\s*title|section\s*title|follow\s*prompt|cover\s*title|brand\s*page|opening\s*page)[^。.!?;；\n]*[。.!?;；]?",
        r"[^。.!?;；\n]*(?:书名|章节信息|章节标题|章节序号|作者|版本|副标题|页标题|封面|首页|品牌页)[^。.!?;；\n]*[。.!?;；]?",
    ]
    for pat in forbidden_patterns:
        p = re.sub(pat, " ", p, flags=re.IGNORECASE)
    p = re.sub(r"\b(?:title|subtitle|caption|legend)\s*:\s*", " ", p, flags=re.IGNORECASE)
    p = re.sub(r"\s+", " ", p).strip()
    return p


def _strip_existing_public_locks(prompt: str) -> str:
    """删除旧版本重复公共规格块，避免同一提示词越跑越长。"""
    p = str(prompt or "").replace("\r\n", "\n").replace("\r", "\n")
    markers = [
        "GLOBAL NON-NEGOTIABLE IMAGE RULES:",
        "PUBLIC ELEMENT SINGLE SOURCE OF TRUTH:",
        "PAGE TYPE LOCK:",
        "PUBLIC BRAND LOCK:",
        "Fixed public palette:",
    ]
    for marker in markers:
        pos = p.find(marker)
        if pos >= 0:
            p = p[:pos].strip()
    return re.sub(r"\s+", " ", p).strip()



def strip_public_elements_for_raw_generation(prompt: str, role: str = "") -> str:
    """移除会导致模型生成公共元素的片段，但保留该图自己的主体画面描述。"""
    p = str(prompt or "").replace("\r\n", "\n").replace("\r", "\n")
    kept = []
    for line in p.splitlines():
        t = line.strip()
        if not t:
            continue
        if role in {"tweet_cover_27_36", "cover_27_48", "brand_end_page_27_48"}:
            # 不整行丢弃，避免“标题/Logo + 主体构图”写在同一行时把主体也删掉。
            t = re.sub(r"(?:QuanLan\s*BrainScience\s*®?|全澜脑科学®?)", " ", t, flags=re.I)
            t = re.sub(r"(?:logo|watermark|brand|book\s*title|chapter\s*title|chapter\s*number|author\s*line|slogan|follow|CTA|QR|关注|公众号|书名|章节标题|章节序号|作者|标题|副标题)\s*[：:=]?\s*[\"“]?[^。.!?;；\n\"”]{0,160}[\"”]?[。.!?;；]?", " ", t, flags=re.I)
            t = re.sub(r'(?:text|visible\s+text|render\s+text)\s*[：:=]?\s*["“][^"”]{1,160}["”]', " ", t, flags=re.I)
        else:
            t = sanitize_content_prompt_text_policy(sanitize_content_prompt_brand_text(t))
        t = re.sub(r"\s+", " ", t).strip(" ,，.;；。")
        if t:
            kept.append(t)
    p = " ".join(kept)
    p = re.sub(r"\s+", " ", p).strip()
    if not p:
        if role in {"tweet_cover_27_36", "cover_27_48"}:
            p = "No-text active-style background with one concrete source-supported chapter motif."
        elif role == "brand_end_page_27_48":
            p = "No-text chapter-related scientific ending background with one concrete biomedical motif connected to the chapter theme."
        else:
            p = "No-text active-style content illustration with one concrete source-supported concept and an explicit visual relationship."
    return p




def _compact_generation_prompt_text(prompt: str, max_chars: int | None = None) -> str:
    """清洗绘图 API 主体提示词：只删公共噪声和重复句，不再按字符数截断。"""
    raw = str(prompt or "").replace("\r\n", "\n").replace("\r", "\n")
    raw = _strip_existing_public_locks(raw)
    # 删除最耗 token 且由程序/接口控制的尺寸、坐标、字体、色值长规格；不整段截断，避免丢掉主体画面。
    raw = re.sub(r"\bcanvas\s*size\s*[:=]?\s*\d{3,5}\s*x\s*\d{3,5}[.;；。]?", " ", raw, flags=re.I)
    raw = re.sub(r"\bfont\s*size\s*[:=]?\s*\d{1,4}\s*px?[.;；。]?", " ", raw, flags=re.I)
    raw = re.sub(r"\b(?:canvas|size|resolution|aspect ratio|ratio|dpi|font|fontsize|center_[xy]|x|y|width|height)\s*[:=][^.;；。\n]+[.;；。]?", " ", raw, flags=re.I)
    raw = re.sub(r"#[0-9A-Fa-f]{6}", " ", raw)
    raw = re.sub(r"\b\d{3,5}\s*x\s*\d{3,5}\b", " ", raw, flags=re.I)
    raw = re.sub(r"\b\d{2,4}\s*px\b", " ", raw, flags=re.I)
    raw = re.sub(r"\bNo\s*(?=[.;；。]|$)", " ", raw, flags=re.I)
    # 合并重复句；对公共禁令只保留后面的短协议，不在主体里重复。
    public_noise = re.compile(r"(no\s+(?:visible\s+)?(?:logo|watermark|brand|title|cta|qr)|do not render|software[- ]stamped|public elements|公共元素|后处理|水印|品牌|标题)", re.I)
    parts = re.split(r"(?<=[。.!?；;])\s+|\n+", raw)
    seen, kept = set(), []
    for part in parts:
        text = part.strip(" \t\n,，")
        if not text:
            continue
        if public_noise.search(text):
            continue
        key = re.sub(r"\s+", " ", text).lower()
        if key in seen:
            continue
        seen.add(key)
        kept.append(text)
    text = " ".join(kept).strip()
    return re.sub(r"\s+", " ", text).strip()



SCI_FI_STYLE_NEGATIVE_RE = re.compile(
    r"\b(?:sci[-\s]?fi|science fiction|cyberpunk|futuristic|future tech|neon|HUD|hologram|holographic|data stream|digital dashboard|cinematic 3D|metallic|mecha|spaceship|space age)\b|"
    r"(?:科幻|赛博朋克|霓虹|全息|高科技界面|数据流|金属机甲|太空感)",
    flags=re.I,
)


def sanitize_cell_style_subject_text(prompt: str) -> str:
    """把单张图主体描述中的科幻/霓虹/HUD/文字标签倾向清掉，统一回 严谨医学插画风格。"""
    p = str(prompt or "")
    p = SCI_FI_STYLE_NEGATIVE_RE.sub(" ", p)
    p = re.sub(r"\b(?:with|including|add|show)\s+(?:visible\s+)?(?:text|letters|numbers|labels|captions|legends|logos?)\b", " ", p, flags=re.I)
    p = re.sub(r"(?:带有|加入|显示|包含)(?:文字|字母|数字|标签|图例|标题|logo|标志)", " ", p, flags=re.I)
    p = re.sub(r"\s+", " ", p).strip(" ,，.;；。")
    return p

def _hard_cap_visual_prompt_text(prompt: str, max_chars: int | None = None, *, tail: str = "") -> str:
    """v8.2：不再硬截断绘图提示词。

    旧版会按 IMAGE_API_HARD_MAX_CHARS 截断，并可能把英文短语截成
    `restrained ac...` 这类半截提示词。新版只做空白规范化和尾部规则追加，
    不切词、不切句、不切段。若用户确实需要压缩，应在上游重写提示词，
    不能在这里机械截断。
    """
    text = re.sub(r"\s+", " ", str(prompt or "")).strip()
    if not text:
        return ""
    tail = re.sub(r"\s+", " ", str(tail or "")).strip()
    if tail and tail not in text:
        text = (text.rstrip(" ,，.;；。") + " " + tail).strip()
    return text



def _build_concise_b_teaching_api_prompt(voice: str, original_prompt: str = "") -> str:
    """B 系列最终发给图像 API 的短硬提示词：台词相关 + 关键词示意，禁止大段说明文字。"""
    summary = _summarize_voiceover_for_visual_lock(voice, limit=180)
    strict_target = _strict_b_visual_target_from_voiceover(voice) if '_strict_b_visual_target_from_voiceover' in globals() else ""
    anchors = _voiceover_visual_keywords(voice) if '_voiceover_visual_keywords' in globals() else ""
    logic = _voiceover_logic_relation_brief(voice) if '_voiceover_logic_relation_brief' in globals() else ""

    logic_lower = str(logic or "").lower()
    layout_hint = "single clean teaching scene"
    if "comparison" in logic_lower or "contrast" in logic_lower:
        layout_hint = "very simple side-by-side comparison"
    elif "sequence" in logic_lower or "process" in logic_lower or "stepwise" in logic_lower or "temporal" in logic_lower:
        layout_hint = "simple visual flow, max 2-3 visual states, no numbered text"
    elif "evidence-to-claim" in logic_lower or "observation" in logic_lower or "experimental" in logic_lower:
        layout_hint = "single evidence scene with one small readout motif"
    elif "input-output" in logic_lower or "feedback" in logic_lower or "pathway" in logic_lower or "mechanistic linkage" in logic_lower or "cause-to-effect" in logic_lower:
        layout_hint = "single causal mechanism scene with arrows"
    elif "hierarchy" in logic_lower or "zoom" in logic_lower:
        layout_hint = "simple macro-to-micro zoom, max one inset"

    short_anchor = ""
    if anchors:
        parts = [x.strip() for x in str(anchors).split(';') if x.strip()]
        kept = []
        for part in parts:
            if strict_target and part == strict_target:
                continue
            kept.append(part)
            if len(kept) >= 1:
                break
        short_anchor = "; ".join(kept)

    lines = [
        "B-SERIES VOICEOVER-MATCHED KEYWORD DIAGRAM.",
        f"Paired voiceover meaning: {summary}.",
        f"Visual target: {strict_target or summary}.",
        f"Layout: {layout_hint}; one main visual focus only.",
        "Show the relationship mainly through biomedical objects, arrows, spatial arrangement, and color contrast; do not write mechanism explanations inside the image.",
        "Visible text policy: keep labels minimal. If labels help scientific clarity, use only 2-4 English keyword labels/callouts total, each 1-2 words. Keywords only, no sentences.",
        "Forbidden visible text: title, header, footer, paragraph, caption, explanation box, numbered steps, bullet list, table, dense labels, Chinese text, pseudo-text, logo, watermark.",
        "Accuracy: every visible object must be supported by the paired voiceover; remove neighboring-shot details and decorative filler.",
        "Style: clean professional biomedical textbook illustration, crisp contour linework, light neutral background, restrained academic colors, slight dimensional depth, not a poster, not an infographic board, not cinematic CGI.",
    ]
    if short_anchor:
        lines.append(f"Optional supported anchor: {short_anchor}.")
    out = re.sub(r"\s+", " ", " ".join(lines)).strip()
    tail = "Final B rules: match the paired voiceover; one clean teaching figure; keyword labels only when helpful: 2-4 English labels, 1-2 words each. No title, paragraph, caption, explanation box, table, numbered steps, Chinese text, pseudo-text, logo, watermark."
    return _hard_cap_visual_prompt_text(out, max_chars=None, tail=tail)

def enforce_canonical_visual_spec(prompt: str, prompt_name: str = "") -> str:
    """绘图前统一改成 raw 图提示词：优先用配对台词重建主体，避免图文不一致。"""
    raw0 = _strip_existing_public_locks(prompt)
    role = detect_visual_role(prompt_name, raw0)
    if role == "daily_research_square_visual_summary":
        square_tail = (
            "Daily research square visual summary contract: compose the complete scientific mechanism directly inside one 1:1 square canvas. "
            "Do not create a tall mobile poster, vertical full-body animal anatomy poster, page screenshot, infographic board, or layout that depends on cropping. "
            "All essential structures, arrows, insets, and mechanism stages must fit inside the square with balanced margins. "
            "No visible text, letters, numbers, captions, logo, watermark, pseudo-text, UI, title, header, footer, or paragraph. "
            "Use a Cell-style biomedical visual abstract aesthetic with clear mechanism-first composition."
        )
        return _hard_cap_visual_prompt_text(raw0, max_chars=None, tail=square_tail)
    page_type = infer_alignment_page_type(prompt_name, raw0)
    # A/C 提示词会包含全章摘要，其中可能出现 A1/A2/A01/A02 字样；
    # 页型必须优先相信文件名/角色，避免 C 品牌页被误判成 A 系列封面。
    if role == "brand_end_page_27_48":
        page_type = "C. Brand Page"
    elif role in {"tweet_cover_27_36", "cover_27_48", "home_page_27_48", "bilibili_cover_4_3", "bilibili_home_16_9"}:
        page_type = "A1/A2/A01/A02 Shared Master/Crop Page"
    paired_voice = _extract_paired_voiceover_from_prompt(raw0)
    global_theme = _extract_global_script_theme_from_prompt(raw0)
    theme_voice = global_theme if role in {"tweet_cover_27_36", "cover_27_48", "home_page_27_48", "bilibili_cover_4_3", "bilibili_home_16_9", "brand_end_page_27_48"} and global_theme else paired_voice

    if theme_voice:
        if role == "content_diagram_27_48" and paired_voice:
            # v6.5: B 系列用短硬教学提示词，避免长提示词被预算截断后准确性约束丢失。
            return _build_concise_b_teaching_api_prompt(paired_voice, original_prompt=raw0)
        body = _build_voiceover_grounded_visual_brief(theme_voice, page_type=page_type, original_prompt=raw0)
    elif role in {"tweet_cover_27_36", "cover_27_48", "home_page_27_48", "bilibili_cover_4_3", "bilibili_home_16_9"}:
        body = strip_public_elements_for_raw_generation(raw0, role=role)
        body = _compact_generation_prompt_text(body, max_chars=IMAGE_BODY_PROMPT_BUDGET_CHARS)
        if not body:
            body = "Create one shared no-text A1/A2 explanatory biomedical key visual with slight dimensional depth and a chapter-relevant concrete biology motif, pale high-key light neutral background, restrained blue-white palette, low visual density, soft low-contrast supportive background, non-sci-fi; prefer a summary-figure feeling, not generic wallpaper or title placeholder. The overall background should stay lighter and calmer so later typography remains easy to read."
    elif role == "brand_end_page_27_48":
        body = strip_public_elements_for_raw_generation(raw0, role=role)
        body = _compact_generation_prompt_text(body, max_chars=IMAGE_BODY_PROMPT_BUDGET_CHARS)
        if not body:
            body = "Create a no-text ending/brand page explanatory biomedical key visual with slight dimensional depth related to the chapter topic, pale high-key light neutral background, restrained blue-white palette, low visual density, soft low-contrast supportive background, non-sci-fi; no generic end-card wallpaper or text placeholder. The overall background should stay lighter and calmer so later typography remains easy to read."
    else:
        body = strip_public_elements_for_raw_generation(raw0, role=role)
        body = _compact_generation_prompt_text(body, max_chars=IMAGE_BODY_PROMPT_BUDGET_CHARS)
        if not body:
            body = "No-text neuroscience biomedical mechanism base illustration relevant to this chapter, explanation-first biomedical illustration aesthetic with slight dimensional depth, restrained blue-white academic palette, light neutral background, optional subtle supportive background, non-sci-fi."

    # v140 hard reset: keep the semantic visual brief FIRST. 旧版把长通用规则放在前面，
    # 触发预算截断后只剩泛化背景，具体台词和逻辑关系被切掉。
    if role not in {"tweet_cover_27_36", "cover_27_48", "home_page_27_48", "bilibili_cover_4_3", "bilibili_home_16_9", "brand_end_page_27_48"}:
        body = body + " Relationship-first rule: the final raw image must be understandable as this narration's concept relationship, not as a generic topic background. Prefer a diagram-first textbook figure, cross-section, cutaway, exploded view, or comparison panel rather than a cinematic close-up."
    else:
        if role in {"tweet_cover_27_36", "cover_27_48", "home_page_27_48", "bilibili_cover_4_3", "bilibili_home_16_9", "brand_end_page_27_48"}:
            body = body + " A/C full-chapter summary rule: this must read as a chapter-level biomedical concept map that summarizes the whole chapter's problem, objects, mechanism/evidence chain and conclusion/next-question relationship; it must visibly include multiple concrete chapter elements rather than a single floating icon. Prefer at least 3 source-supported components for A-series and at least 2-4 recap components for C page, with explicit macro-micro or evidence/mechanism relationships when supported. Never use only generic biology symbols, generic brain/neurons/DNA/cells, decorative particles, medical wallpaper, or brand atmosphere."
        else:
            body = body + " Theme-specific rule: use a concrete motif from the chapter theme, not a generic decorative wallpaper."

    body = sanitize_cell_style_subject_text(body)
    if role == "content_diagram_27_48":
        contract = (
            "B-SERIES CONTRACT: flat or lightly shaded educational biomedical diagram matched to the paired voiceover. Prefer zero visible text; if needed, allow only 1-3 concise English keyword labels/callouts total, each 1-2 words, plus simple arrows. No short section headers. "
            "No title, no paragraph, no caption, no explanation box, no numbered steps, no bullet list, no table, no dense label clusters, no Chinese text, no logo, no watermark, no pseudo-text, no UI, no HUD, no cyberpunk, no neon sci-fi, no decorative random particles. "
            "Use an explanation-first biomedical illustration look with medically plausible morphology, clear structure relationships, crisp contour linework, light neutral background, minimal perspective distortion, and textbook-figure clarity."
        )
    else:
        contract = (
            "RAW CONTRACT: no visible text, no letters, no numbers, no labels, no captions, no logo, "
            "no watermark, no pseudo-text, no UI, no HUD, no cyberpunk, no neon sci-fi, no decorative random particles. "
            "Use an explanation-first biomedical illustration look with medically plausible morphology, clear structure relationships, crisp contour linework, soft dimensional shading, clean color separation, light neutral background, and explanation-first clarity. Allow slight 3D depth and subtle volume, but avoid flashy CGI, photoreal translucency, glossy rendering, and dramatic depth effects. "
            "All fixed typography, arrows, labels, logo, reference lines and masks are post-processing only."
        )
    locked = f"{body}\n{contract}"
    if len(locked) > IMAGE_API_PROMPT_BUDGET_CHARS:
        keep = max(720, IMAGE_API_PROMPT_BUDGET_CHARS - len(contract) - 2)
        body = body[:keep].rstrip(" ,，.;；。")
        locked = f"{body}\n{contract}"
    return re.sub(r"\s+", " ", locked).strip()



