# 生成脚本之后不再对“绘图提示词文件”做结构化精简；以下旧辅助函数保留为兼容入口。
def _first_visual_lock_marker_index(prompt: str) -> int:
    markers = [
        "GLOBAL IMAGE RULES — INCLUDE IN EVERY SINGLE IMAGE PROMPT",
        "CONTENT PAGE SOFTWARE LOGO LOCK — DO NOT DRAW LOGO IN THE RAW IMAGE",
        "ABSOLUTE B-TYPE LOGO LOCK",
        "SCIENTIFIC ACCURACY GUARDRAIL:",
        "CONTENT VISUAL RICHNESS SPEC:",
        "SERIES COVER / OPENING PAGE LAYOUT LOCK",
        "UNIFIED VISUAL SPEC",
    ]
    positions = [str(prompt or "").find(m) for m in markers if str(prompt or "").find(m) >= 0]
    return min(positions) if positions else -1


def _base_image_idea_from_prompt(prompt: str) -> str:
    """只抽取这张图自己的主体构图描述，剥离后面注入过的公共规则。"""
    p = re.sub(r"\s+", " ", str(prompt or "")).strip()
    cut = _first_visual_lock_marker_index(p)
    if cut > 0:
        p = p[:cut].strip()
    # 去掉少数模型可能直接写进主体段的参数说明，避免独立提示词里重复堆规格。
    p = re.sub(r"These are production instructions[^。.!?;；\n]*[。.!?;；]?", " ", p, flags=re.I)
    p = re.sub(r"Do not render the specification words themselves[^。.!?;；\n]*[。.!?;；]?", " ", p, flags=re.I)
    p = re.sub(r"\s+", " ", p).strip()
    return p


def _extract_visible_text_items_from_prompt(prompt: str) -> list[str]:
    """从旧版长提示词里提取 text "..." 可见文案，便于压缩封面/品牌页。"""
    items = []
    for m in re.finditer(r'text\s+["“]([^"”]{1,160})["”]', str(prompt or ""), flags=re.I):
        value = m.group(1).strip()
        if value and value not in items and not re.search(r"x=|y=|px|opacity|font|Canvas size", value, flags=re.I):
            items.append(value)
    return items[:10]


def _remove_verbose_visual_specs(prompt: str) -> str:
    """删除最耗 token 的像素坐标、字体参数、全局规则和重复负面约束。"""
    p = str(prompt or "").replace("\r\n", "\n").replace("\r", "\n")
    # 先切掉旧模板中从 Canvas size 开始的大块像素/坐标规格；主体画面描述通常在它之前。
    cut_markers = [
        "Canvas size:", "【A1 Mandatory", "【A2 Mandatory", "【B-type Mandatory", "【C-type Mandatory",
        "GLOBAL IMAGE RULES", "Global Image Rules", "ABSOLUTE B-TYPE LOGO LOCK",
        "Public Frame Lock", "Top Logo Frame Lock", "Central Text Group Frame Lock",
    ]
    cut_positions = [p.find(x) for x in cut_markers if p.find(x) >= 0]
    if cut_positions:
        p = p[:min(cut_positions)]
    # 删除残留的坐标/字号/颜色/比例句。
    p = re.sub(r"\b(?:x|y|width|height|center x|center y|size|font|opacity|ratio)\s*=\s*[^,.;；。\n]+[,.;；。]?", " ", p, flags=re.I)
    p = re.sub(r"#[0-9A-Fa-f]{6}", " ", p)
    p = re.sub(r"\b\d{3,4}\s*x\s*\d{3,4}\b", " ", p, flags=re.I)
    p = re.sub(r"\b\d{2,4}\s*px\b", " ", p, flags=re.I)
    p = re.sub(r"\s+", " ", p).strip(" +")
    return p


def _compact_role_spec(role: str, visible_items: list[str] | None = None) -> str:
    """旧压缩入口兼容：不再要求模型绘制公共文字，全部留给后处理。"""
