def apply_professional_terminology_cleanup(script_text: str) -> str:
    """保存前的专业术语兜底清洗。只做高置信、固定错误译法替换。"""
    if not script_text:
        return script_text
    cleaned = script_text
    for bad, good in PROFESSIONAL_TERMINOLOGY_REPLACEMENTS.items():
        cleaned = cleaned.replace(bad, good)
    banned_intro_phrases = [
        "所有知识点均严格依据原文逻辑展开。",
        "所有知识点均严格依据原文逻辑展开",
        "全文知识点均严格依据原文逻辑展开。",
        "全文知识点均严格依据原文逻辑展开",
    ]
    for phrase in banned_intro_phrases:
        cleaned = cleaned.replace(phrase, "")

    # 开场介绍句兜底：避免‘本期解读的是……今天分享的章节是……’重复介绍。
    # 只处理高置信固定句式，不改变科学内容。
    cleaned = re.sub(
        r"本期解读的是([^。；;!?！？]{1,80}?)。?今天分享的章节是[:：]?\s*",
        r"今天继续分享\1的",
        cleaned
    )
    cleaned = re.sub(
        r"今天继续分享([^。；;!?！？]{1,80}?)的的",
        r"今天继续分享\1的",
        cleaned
    )
    cleaned = cleaned.replace("本期解读的是", "今天继续分享")

    # 高置信论文腔/机翻腔兜底：避免保存时残留特别生硬的固定句式。
    academic_phrase_replacements = {
        "这为理解行为状态转换提供了分子基础。": "这样看，行为状态的切换，可能要先从分子层面说起。",
        "这为理解行为状态转换提供了分子基础": "这样看，行为状态的切换，可能要先从分子层面说起",
        "这提示我们该机制具有重要意义。": "这一步把问题往前推了一层。",
        "这提示我们该机制具有重要意义": "这一步把问题往前推了一层",
        "这揭示了该机制的重要意义。": "这让这个机制的作用更清楚了。",
        "这揭示了该机制的重要意义": "这让这个机制的作用更清楚了",
        "为理解这一过程提供了基础。": "让我们可以从这里开始理解这个过程。",
        "为理解这一过程提供了基础": "让我们可以从这里开始理解这个过程",
        "这为理解行为状态转换提供了分子基础。": "这样看，行为状态的切换，可能要先从分子层面的调节说起。",
        "这为理解行为状态转换提供了分子基础": "这样看，行为状态的切换，可能要先从分子层面的调节说起",
    }
    for bad, good in academic_phrase_replacements.items():
        cleaned = cleaned.replace(bad, good)
    return cleaned


def sanitize_sentence_clarity_and_redundancy(text: str) -> str:
    """保存前清理高置信的语病、重复修饰和不完整表意；只做保守句法修正。"""
    if not text:
        return text
    t = str(text)

    fixed_replacements = {
        "涉及慢速突触调节和第二信使对神经元兴奋性的长效改变。": "本章从较慢的突触调节过程讲起，重点说明代谢型受体和第二信使通路。它们可以在较长时间尺度上调节神经元兴奋性。",
        "涉及慢速突触调节和第二信使对神经元兴奋性的长效改变": "本章从较慢的突触调节过程讲起，重点说明代谢型受体和第二信使通路。它们可以在较长时间尺度上调节神经元兴奋性",
        "慢速突触调节和第二信使对神经元兴奋性的长效改变": "通过代谢型受体和第二信使通路，对神经元兴奋性进行较慢、较持久的调节",
        "第二信使对神经元兴奋性的长效改变": "第二信使通路对神经元兴奋性的较持久调节",
        "神经元兴奋性的长效改变": "神经元兴奋性的较持久调节",
        "慢速突触调节": "较慢的突触调节过程",
        "这类受体反应极快且短暂，且持续时间短暂。": "这类受体介导的反应通常起效快、持续时间短。",
        "这类受体反应极快且短暂， 且持续时间短暂。": "这类受体介导的反应通常起效快、持续时间短。",
        "这类受体反应极快且短暂，且持续时间短暂": "这类受体介导的反应通常起效快、持续时间短",
        "这类受体反应极快且短暂， 且持续时间短暂": "这类受体介导的反应通常起效快、持续时间短",
        "反应极快且短暂，且持续时间短暂": "反应起效快、持续时间短",
        "反应极快且短暂， 且持续时间短暂": "反应起效快、持续时间短",
        "作用很快且短暂，且持续时间短暂": "作用出现较快，持续时间较短",
        "快速短暂，且持续时间短暂": "起效快，持续时间短",
        "很短暂且持续时间短暂": "持续时间短",
        "持续时间短暂": "持续时间短",
    }
    for bad, good in fixed_replacements.items():
        t = t.replace(bad, good)

    # 清理同一句中连续重复的“短暂/短/很快/快速”等修饰，避免“短暂，且持续时间短”一类冗余。
    t = re.sub(r"([^。！？\n]{0,40}?)(?:极快|很快|快速)且短暂[，,、]?\s*且(?:持续时间)?(?:也)?(?:很)?短(?:暂)?", r"\1起效快、持续时间短", t)
    t = re.sub(r"([^。！？\n]{0,40}?)短暂[，,、]?\s*且持续时间短", r"\1持续时间短", t)

    t = re.sub(r"短暂[，,、]?\s*且短暂", "短暂", t)

    # 保持口播句子表意完整：避免“且……”孤立悬挂。
    t = re.sub(r"([。！？；;])\s*且", r"\1同时", t)

    # 清理多余空格和中文标点前空格。
    t = re.sub(r"[ \t]+([，。！？；：、])", r"\1", t)
    t = re.sub(r"([，。！？；：、])[ \t]+", r"\1", t)
    return t


def sanitize_final_chinese_logic_and_professional_expression(text: str) -> str:
    """保存前最后一层中文审校：修正高置信的不地道专业表达、抽象名词堆叠和逻辑压缩句。"""
    if not text:
        return text

    t = str(text)

    # 高置信专业表达修正：只改明确不自然或过度压缩的固定句式，避免误改原文含义。
    professional_replacements = {
        "涉及慢速突触调节和第二信使对神经元兴奋性的长效改变。": "本章从较慢的突触调节过程讲起，重点说明代谢型受体和第二信使通路。它们可以在较长时间尺度上调节神经元兴奋性。",
        "涉及慢速突触调节和第二信使对神经元兴奋性的长效改变": "本章从较慢的突触调节过程讲起，重点说明代谢型受体和第二信使通路。它们可以在较长时间尺度上调节神经元兴奋性",
        "涉及较慢的突触调节过程和第二信使通路对神经元兴奋性的较持久调节。": "本章从较慢的突触调节过程讲起，重点说明代谢型受体和第二信使通路。它们可以在较长时间尺度上调节神经元兴奋性。",
        "慢速突触调节": "较慢的突触调节过程",
        "长效改变": "较持久的调节",
        "对神经元兴奋性的长效改变": "对神经元兴奋性的较持久调节",
        "第二信使对神经元兴奋性的长效改变": "第二信使通路对神经元兴奋性的较持久调节",
    }
    for bad, good in professional_replacements.items():
        t = t.replace(bad, good)

    # 避免“涉及A和B”这类压缩式开场句。只处理短句，改成更完整的说明结构。
    t = re.sub(
        r"口播文案[：:]\s*涉及([^。！？\n]{4,80})。",
        lambda m: "口播文案：这一部分需要说明" + m.group(1).strip() + "之间的关系。",
        t
    )

    # 清理抽象名词堆叠导致的“X和Y对Z的……”结构，让语义关系更明确。
    t = re.sub(
        r"第二信使通路和([^，。！？\n]{2,30})对神经元兴奋性的较持久调节",
        r"第二信使通路如何与\1一起，在较长时间尺度上调节神经元兴奋性",
        t
    )

    # 删除或改写无中生有的对比/否定转折，尤其是前文没有铺垫“离子通道”时突然写“不能单靠”。
    unsupported_logic_replacements = {
        "不能仅靠快速的电信号解释，这就需要引入慢速的突触调节与第二信使机制。":
            "这一部分进入本章的主线：较慢的突触调节过程，以及第二信使通路如何参与神经元兴奋性的调节。",
        "不能仅靠快速的电信号解释，这就需要引入慢速的突触调节与第二信使机制":
            "这一部分进入本章的主线：较慢的突触调节过程，以及第二信使通路如何参与神经元兴奋性的调节",
        "不能仅靠快速电信号解释，这就需要引入慢速的突触调节与第二信使机制。":
            "这一部分进入本章的主线：较慢的突触调节过程，以及第二信使通路如何参与神经元兴奋性的调节。",
        "不能仅靠快速电信号解释，这就需要引入慢速的突触调节与第二信使机制":
            "这一部分进入本章的主线：较慢的突触调节过程，以及第二信使通路如何参与神经元兴奋性的调节",
        "这种现象不能仅靠快速的电信号解释，这就需要引入慢速的突触调节与第二信使机制。":
            "接下来要看的，是较慢的突触调节过程，以及第二信使通路如何参与神经元兴奋性的调节。",
        "这种现象不能仅靠快速的电信号解释，这就需要引入慢速的突触调节与第二信使机制":
            "接下来要看的，是较慢的突触调节过程，以及第二信使通路如何参与神经元兴奋性的调节",
        "这种状态的维持，不能单靠快速开启的离子通道来解释。本章讨论的是，神经递质如何通过代谢型受体启动第二信使通路，并在较长时间尺度上调节神经元的兴奋性。":
            "本章从突触传递的时间尺度讲起。原文进一步讨论代谢型受体和第二信使通路如何参与较慢、较持久的兴奋性调节。",
        "这种状态的维持，不能单靠快速开启的离子通道来解释。":
            "原文在快速突触传递之外，进一步讨论较慢的调节过程。",
        "不能单靠快速开启的离子通道来解释。":
            "还需要说明较慢的受体通路如何参与调节。",
        "本章讨论的是，神经递质如何通过代谢型受体启动第二信使通路，并在较长时间尺度上调节神经元的兴奋性。":
            "本章重点说明代谢型受体和第二信使通路。它们可以在较长时间尺度上调节神经元兴奋性。",
    }
    for bad, good in unsupported_logic_replacements.items():
        t = t.replace(bad, good)

    # 禁止无铺垫的“快速电信号 vs 慢速第二信使”对比。若前文没有明确交代比较对象，改成顺接的主题进入句。
    t = re.sub(
        r"(?:这种(?:状态|现象|变化)[^。！？]{0,20})?不能(?:单靠|仅靠)[^。！？]{0,18}(?:快速|快)[^。！？]{0,18}(?:电信号|离子通道|突触传递)[^。！？]{0,20}(?:解释|说明)[，,。；;]?\s*(?:这就|因此|所以|于是)?(?:需要|要)?(?:引入|进入|转向)[^。！？]{0,30}(?:慢速|较慢)[^。！？]{0,30}(?:第二信使|代谢型受体)[^。！？]*[。！？]?",
        "这一部分进入本章的主线：较慢的突触调节过程，以及第二信使通路如何参与神经元兴奋性的调节。",
        t
    )
    t = re.sub(
        r"(?:这种(?:状态|现象|变化)[^。！？]{0,20})?不能(?:单靠|仅靠)[^。！？]{0,18}(?:快速|快)[^。！？]{0,18}(?:电信号|离子通道|突触传递)[^。！？]{0,20}(?:解释|说明)[。！？]",
        "接下来原文把讨论推进到较慢的突触调节过程。",
        t
    )

    # 拆分“本章讨论的是，A如何通过B，并在C上D”这类长难句。
    t = re.sub(
        r"本章讨论的是，神经递质如何通过代谢型受体启动第二信使通路，并在较长时间尺度上调节神经元的兴奋性。",
        "本章重点说明代谢型受体和第二信使通路。神经递质可以通过这些通路，在较长时间尺度上调节神经元兴奋性。",
        t
    )

    # 结尾品牌页兜底：如果模型只写了公众号引导，至少补上“本期总结/下期预告/关注引导”的结构提醒。
    t = t.replace("这篇研究的快速导读就先到这。关注我们，下一章，我们将继续讲解相关神经科学问题。",
                  "本期我们梳理了这项研究的核心问题、证据线索和主要结论。下期将继续围绕相关神经科学问题展开。关注我们，下一章，我们将继续讲解相关神经科学问题。")
    t = t.replace("关注我们，下一章，我们将继续讲解相关神经科学问题。",
                  "关注我们，下一章，我们将继续讲解相关神经科学问题。")

    # 删除模型误写进脚本的“写作要求/审校要求”，这些不是口播内容。
    meta_instruction_patterns = [
        r"(?m)^\s*[-•*]?\s*口播文案[：:]\s*钩子案例要贴合内容[^\n。！？]*[。！？]?\s*$",
        r"(?m)^\s*[-•*]?\s*口播文案[：:]\s*不要有这种无意义的口水话[^\n。！？]*[。！？]?\s*$",
        r"(?m)^\s*[-•*]?\s*口播文案[：:]\s*.*不要悬浮编造[^\n。！？]*[。！？]?\s*$",
        r"(?m)^\s*[-•*]?\s*口播文案[：:]\s*.*贴合内容且与生活相关[^\n。！？]*[。！？]?\s*$",
        r"(?m)^\s*[-•*]?\s*口播文案[：:]\s*.*引发观众共鸣[^\n。！？]*[。！？]?\s*$",
    ]
    for pat in meta_instruction_patterns:
        t = re.sub(pat, "", t)

    # 句子层面的轻量清洁：避免连续逗号、标点前后空格、空句。
    t = re.sub(r"，{2,}", "，", t)
    t = re.sub(r"。{2,}", "。", t)
    t = re.sub(r"[ \t]+([，。！？；：、])", r"\1", t)
    t = re.sub(r"([，。！？；：、])[ \t]+", r"\1", t)
    t = re.sub(r"(?m)^\s*[-•*]?\s*口播文案[：:]\s*[。；;]?\s*$", "", t)
    return t
